(function(){
  PyLearn.createEditor({
    containerId: 'editor-fp',
    initialCode: '# Use a for loop to print Yes four times\n',
    label: 'Mini Practice',
    validate: async function(output, error, code) {
      if (error) return { pass: false, message: '\u274c Problem: ' + error };
      if (output.trim() === 'Yes\nYes\nYes\nYes') {
        if (!/for/.test(code)) return { pass: false, message: '\u26a0\ufe0f Right answer, but please use a for loop.' };
        return { pass: true, message: '\u2705 Brilliant!' };
      }
      var lines = output.trim().split('\n');
      if (lines.length !== 4) return { pass: false, message: '\u274c We need exactly 4 lines. You have ' + lines.length + '.' };
      return { pass: false, message: '\u274c Each line should be the word: Yes' };
    },
    onPass: async function() { await window.__markStepComplete(); }
  });
})();

(function(){
  PyLearn.createEditor({
    containerId: 'editor-rp',
    initialCode: '# Print 5 to 15\n',
    label: 'Mini Practice',
    validate: async function(output, error, code) {
      if (error) return { pass: false, message: '\u274c Problem: ' + error };
      var expected = '';
      for (var i = 5; i <= 15; i++) expected += i + (i < 15 ? '\n' : '');
      if (output.trim() === expected) {
        if (!/for/.test(code)) return { pass: false, message: '\u26a0\ufe0f Right answer, but please use a for loop.' };
        return { pass: true, message: '\u2705 Perfect counting!' };
      }
      var lines = output.trim().split('\n');
      if (lines[0] !== '5') return { pass: false, message: '\u274c First number should be 5, not ' + lines[0] };
      if (lines[lines.length-1] !== '15') return { pass: false, message: '\u274c Last number should be 15, not ' + lines[lines.length-1] };
      return { pass: false, message: '\u274c Numbers don\'t match. Check your range.' };
    },
    onPass: async function() { await window.__markStepComplete(); }
  });
})();

