(function(){
  function buildExpected() {
    var lines = [];
    for (var i = 1; i <= 30; i++) {
      if (i % 15 === 0) lines.push('FizzBuzz');
      else if (i % 3 === 0) lines.push('Fizz');
      else if (i % 5 === 0) lines.push('Buzz');
      else lines.push(String(i));
    }
    return lines.join('\n');
  }
  var expected = buildExpected();
  PyLearn.createEditor({
    containerId: 'editor-fbz',
    initialCode: '# FizzBuzz for 1 to 30\nfor i in range(1, 31):\n    # Your if/elif/else here\n    pass\n',
    label: 'FizzBuzz Challenge',
    validate: async function(output, error, code) {
      if (error) return { pass: false, message: '\u274c Problem: ' + error };
      if (!output.trim()) return { pass: false, message: '\u26a0\ufe0f Nothing was shown. Did you remove the \"pass\" line?' };
      var actual = output.trim();
      if (actual === expected) return { pass: true, message: '\u2705 PERFECT FizzBuzz! You\'re a programmer now!' };
      var aLines = actual.split('\n');
      var eLines = expected.split('\n');
      for (var i = 0; i < 30; i++) {
        if (!aLines[i]) return { pass: false, message: '\u274c Stopped at line ' + (i+1) + '. We expected: ' + eLines[i] };
        if (aLines[i].trim() !== eLines[i]) return { pass: false, message: '\u274c Line ' + (i+1) + ' is wrong. We expected: ' + eLines[i] + ' but got: ' + aLines[i].trim() };
      }
      return { pass: false, message: '\u274c Output doesn\'t match. Check carefully!' };
    },
    onPass: async function() { await window.__markStepComplete(); }
  });
})();

(function(){
  var streak = 0;
  var best = parseInt(localStorage.getItem('pylearn_loops_best') || '0', 10);
  document.getElementById('el-best').textContent = best;

  var challenges = [
    {
      prompt: 'Use a for loop to print the word <strong>Go!</strong> exactly <strong>3 times</strong>.',
      starter: '',
      check: async function(code) {
        var r = await PyLearn.runPython(code);
        if (r.error) return '\u274c Problem: ' + r.error;
        var expected = 'Go!\nGo!\nGo!';
        if (r.output.trim() !== expected) return '\u274c Should show Go! three times, you got: \"' + r.output.trim() + '\"';
        if (!/for/.test(code)) return '\u26a0\ufe0f Please use a for loop.';
        return null;
      }
    },
    {
      prompt: 'Use a for loop to print all the numbers from <strong>1 to 5</strong>.',
      starter: '',
      check: async function(code) {
        var r = await PyLearn.runPython(code);
        if (r.error) return '\u274c Problem: ' + r.error;
        return r.output.trim() === '1\n2\n3\n4\n5' ? null : '\u274c We need 1 to 5 each on their own line.';
      }
    },
    {
      prompt: 'Use a for loop to print the numbers from <strong>10 to 20</strong> (including 20).',
      starter: '',
      check: async function(code) {
        var r = await PyLearn.runPython(code);
        if (r.error) return '\u274c Problem: ' + r.error;
        var expected = '';
        for (var i = 10; i <= 20; i++) expected += i + (i < 20 ? '\n' : '');
        return r.output.trim() === expected ? null : '\u274c We need 10 to 20.';
      }
    },
    {
      prompt: 'Use a for loop to print the <strong>even</strong> numbers from <strong>2 to 10</strong> (including 10).',
      starter: '',
      check: async function(code) {
        var r = await PyLearn.runPython(code);
        if (r.error) return '\u274c Problem: ' + r.error;
        return r.output.trim() === '2\n4\n6\n8\n10' ? null : '\u274c We need: 2, 4, 6, 8, 10 each on their own line.';
      }
    },
    {
      prompt: 'Use a for loop to add up the numbers from <strong>1 to 10</strong> and print the total.',
      starter: 'total = 0\n\n# Loop and add\n\nprint(total)',
      check: async function(code) {
        var r = await PyLearn.runPython(code);
        if (r.error) return '\u274c Problem: ' + r.error;
        return r.output.trim() === '55' ? null : '\u274c The sum of 1 to 10 is 55, you got: \"' + r.output.trim() + '\"';
      }
    },
    {
      prompt: 'Count down from <strong>5 to 1</strong> using a for loop.',
      starter: '',
      check: async function(code) {
        var r = await PyLearn.runPython(code);
        if (r.error) return '\u274c Problem: ' + r.error;
        return r.output.trim() === '5\n4\n3\n2\n1' ? null : '\u274c We need 5, 4, 3, 2, 1 going down.';
      }
    },
    {
      prompt: 'Loop through <strong>1 to 10</strong>. Show <strong>Big</strong> if the number is bigger than 5, otherwise show the number.',
      starter: '',
      check: async function(code) {
        var r = await PyLearn.runPython(code);
        if (r.error) return '\u274c Problem: ' + r.error;
        var expected = '1\n2\n3\n4\n5\nBig\nBig\nBig\nBig\nBig';
        return r.output.trim() === expected ? null : '\u274c Numbers 1-5 should be the number, then \"Big\" five times for 6-10.';
      }
    },
    {
      prompt: 'Print the <strong>3 times table</strong> from 3 up to 30 (3, 6, 9, 12 ... 30) using a for loop.',
      starter: '',
      check: async function(code) {
        var r = await PyLearn.runPython(code);
        if (r.error) return '\u274c Problem: ' + r.error;
        var expected = [3,6,9,12,15,18,21,24,27,30].join('\n');
        return r.output.trim() === expected ? null : '\u274c Should be the 3 times table: 3, 6, 9, 12, ... 30.';
      }
    },
    {
      prompt: 'Use a for loop to count the <strong>multiples of 5</strong> between 1 and 50. Print just the count.',
      starter: 'count = 0\n\n# Loop here\n\nprint(count)',
      check: async function(code) {
        var r = await PyLearn.runPython(code);
        if (r.error) return '\u274c Problem: ' + r.error;
        return r.output.trim() === '10' ? null : '\u274c There are 10 multiples of 5 between 1 and 50, you got: \"' + r.output.trim() + '\"';
      }
    },
    {
      prompt: 'Use a while loop to print the numbers <strong>1, 2, 3, 4, 5</strong>.',
      starter: 'count = 1\n\n# while loop here\n',
      check: async function(code) {
        var r = await PyLearn.runPython(code);
        if (r.error) return '\u274c Problem: ' + r.error;
        if (r.output.trim() !== '1\n2\n3\n4\n5') return '\u274c We need 1 to 5 on separate lines.';
        if (!/while/.test(code)) return '\u26a0\ufe0f Please use a while loop for this one.';
        return null;
      }
    }
  ];

  var currentIdx = -1;

  function pickChallenge() {
    var next;
    do { next = Math.floor(Math.random() * challenges.length); } while (next === currentIdx && challenges.length > 1);
    currentIdx = next;
    return challenges[next];
  }

  function loadChallenge() {
    var ch = pickChallenge();
    document.getElementById('el-prompt').innerHTML = ch.prompt;
    var wrap = document.getElementById('editor-endless');
    wrap.innerHTML = '';
    PyLearn.createEditor({
      containerId: 'editor-endless',
      persist: false,
      initialCode: ch.starter || '# Write your code\n',
      label: 'Endless Mode',
      validate: async function(output, error, code) {
        var msg = await challenges[currentIdx].check(code);
        if (msg) return { pass: false, message: msg };
        return { pass: true, message: '\u2705 Correct! Loading next...' };
      },
      onPass: async function() {
        streak++;
        if (streak > best) {
          best = streak;
          localStorage.setItem('pylearn_loops_best', best);
          document.getElementById('el-best').textContent = best;
        }
        document.getElementById('el-streak').textContent = streak;
        setTimeout(loadChallenge, 1300);
      }
    });
  }

  document.getElementById('el-new').onclick = function() {
    streak = 0;
    document.getElementById('el-streak').textContent = streak;
    loadChallenge();
  };

  loadChallenge();
})();
